import React from "react";
import { Link, useNavigate } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("token");
    navigate("/");
  };

  return (
    <div
      className="d-flex flex-column p-3 text-white"
      style={{
        width: "250px",
        height: "100vh",
        background: "#1f1f1f",
        position: "fixed",
        left: 0,
        top: 0,
        boxShadow: "2px 0 10px rgba(0,0,0,0.2)",
      }}
    >
      <h3 className="text-center mb-4 fw-bold">Sistema de Ventas</h3>

      <ul className="nav nav-pills flex-column mb-auto">
        <li><Link className="nav-link text-white" to="/dashboard">Dashboard</Link></li>
        <li><Link className="nav-link text-white" to="/productos">Productos</Link></li>
        <li><Link className="nav-link text-white" to="/categorias">Categorías</Link></li>
        <li><Link className="nav-link text-white" to="/clientes">Clientes</Link></li>
        <li><Link className="nav-link text-white" to="/ventas">Ventas</Link></li>
        <li><Link className="nav-link text-white" to="/usuarios">Usuarios</Link></li>
      </ul>

      <button
        onClick={handleLogout}
        className="btn btn-danger mt-auto w-100 fw-bold"
      >
        Cerrar sesión
      </button>
    </div>
  );
}
